/** Aggregate SHOW PROCESSLIST / pg_stat rows into total + per-database counts. */

export type ConnectionDbRow = { name: string; count: number; pct: number };

export function findDbColumn(rows: Record<string, unknown>[]): string | null {
  if (!rows.length) return null;
  const keys = Object.keys(rows[0]);
  return (
    keys.find((c) => /^db$/i.test(c)) ??
    keys.find((c) => c === 'database') ??
    keys.find((c) => /^datname$/i.test(c)) ??
    null
  );
}

export function rowDatabaseName(row: Record<string, unknown>, dbCol?: string | null): string {
  const col = dbCol ?? (row ? findDbColumn([row]) : null);
  const raw = col ? row[col] : null;
  return raw == null || String(raw).trim() === '' ? '(sin DB)' : String(raw).trim();
}

export function buildConnectionBreakdown(rows: Record<string, unknown>[]): {
  total: number;
  byDatabase: ConnectionDbRow[];
} {
  const total = rows.length;
  if (!total) return { total: 0, byDatabase: [] };

  const dbCol = findDbColumn(rows);
  const counts = new Map<string, number>();
  for (const r of rows) {
    const name = rowDatabaseName(r, dbCol);
    counts.set(name, (counts.get(name) ?? 0) + 1);
  }

  const byDatabase = [...counts.entries()]
    .map(([name, count]) => ({
      name,
      count,
      pct: total > 0 ? Math.round((count / total) * 100) : 0,
    }))
    .sort((a, b) => b.count - a.count);

  return { total, byDatabase };
}
